entry.content:
项目结构描述
Shiroi 魔改(typo)日志
(解耦合) 标签页
标签页用于显示标题和站点图标.

创建文件layout/_partial/label.ejs.


标签页将实现使用icon.svg为图标
标题可在站点配置文件_config.yml或者主题配置文件_config.shiroi.yml中配置(存在优先关系).

  &lt;!-- 标签页 --&gt;&lt;title&gt;  &lt;%= page.title || config.title || theme.title  %&gt;&lt;/title&gt;&lt;% if (theme.favicon)&#123; %&gt;&lt;%- favicon_tag(theme.favicon) %&gt;&lt;% &#125; %&gt;

在layout/layout.ejs中注入配置

  &lt;!-- 标签页 --&gt;&lt;%- partial(&#x27;_partial/label&#x27;) %&gt;
(解耦合) 字体
字体是全局主题使用的字体,继承了 typo 主题的配置

创建文件layout/_partial/font.ejs.

    &lt;!-- 字体 --&gt;&lt;link rel=&quot;preconnect&quot; href=&quot;https://fonts.googleapis.com&quot;&gt;&lt;link rel=&quot;preconnect&quot; href=&quot;https://fonts.gstatic.com&quot; crossorigin&gt;&lt;link href=&quot;https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,100..900;1,100..900&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;&lt;link href=&quot;https://fonts.googleapis.com/css2?family=JetBrains+Mono:ital,wght@0,100..800;1,100..800&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;

在layout/_partial/global.ejs中注入配置

  &lt;!-- 字体 --&gt;&lt;%- partial(&#x27;_partial/font.ejs&#x27;) %&gt;
(解耦合) 导航栏
导航栏是每个页面最上方的 top bar, 用于展示站点配置文件中的选项menu.

创建文件layout/_partial/header.ejs.


导航栏将实现使用icon.svg为图标
左侧标题可在站点配置文件中配置.
右侧图标可以在icon/文件夹中找到对应名字更换.
右侧图标后名字取决于主题配置文件的 menu 中的配置.

  &lt;!--(头部 top bar) Header 样式 --&gt;&lt;%- css(&#x27;css/header.css&#x27;) %&gt;&lt;header class=&quot;header&quot;&gt;  &lt;section class=&quot;header-container&quot;&gt;    &lt;a class=&quot;header-logo&quot; href=&quot;&lt;%- url_for(&#x27;icon.svg&#x27;) %&gt;&quot;&gt;&lt;%= config.title %&gt;&lt;/a&gt;    &lt;ul class=&quot;header-nav&quot;&gt;      &lt;%        for (const name in theme.menu) &#123;          const iconName = name;      %&gt;      &lt;li&gt;        &lt;a href=&quot;&lt;%- url_for(theme.menu[name]) %&gt;&quot;&gt;          &lt;img src=&quot;&lt;%- url_for(&#x27;icon/&#x27; + iconName + &#x27;.svg&#x27;) %&gt;&quot; alt=&quot;&lt;%= name %&gt; icon&quot; style=&quot;width:1.2em;height:1.2em;vertical-align:middle;&quot;&gt;          &lt;%= name %&gt;        &lt;/a&gt;      &lt;/li&gt;      &lt;% &#125; %&gt;    &lt;/ul&gt;  &lt;/section&gt;&lt;/header&gt;

在layout/layout.ejs中注入配置

  &lt;!-- 导航栏 --&gt;&lt;%- partial(&#x27;_partial/header&#x27;) %&gt;

创建样式文件source/css/header.css

  .header &#123;position: sticky;top: -48px;background: inherit;margin: 0;padding: 64px 8vw 0;max-width: 100%;width: 100%;&#125;.header-container &#123;  display: flex;  justify-content: space-between;  align-items: center;  border-bottom: 1px solid var(--color-hr);&#125;.header-logo &#123;    font-size: 2rem;    font-weight: 600;    color: var(--font-color);    margin-bottom: 16px;&#125;.header-nav &#123;    margin: 0 0 4px;    display: flex;    flex-direction: row;    flex-wrap: wrap;    justify-content: flex-start;    align-content: center;    list-style: none;&#125;.header-nav li &#123;    padding: 2px 0;    margin-right: 24px;&#125;.header-nav li:last-of-type &#123;    margin-right: 0;&#125;.header-nav li a &#123;    color: var(--font-color);&#125;.header-nav li a img &#123;    margin-right: 0.3em;    vertical-align: middle;    display: inline-block;&#125;.header-nav li a:hover &#123;    text-decoration: underline;&#125;
页脚
页脚是底部的版权注释, 可在主题配置文件中的选项copyright修改相关描述.
typo 中已有layout/_partial/footer.ejs文件,用于描述页脚的配置.
数学公式支持

如果你的markdown渲染器和作者一样为hexo-renderer-syzoj-renderer;那么此开关不是必要的；
如果是其他渲染器，可能需要这个开关的支持。


在主题配置文件中添加开关

  mathjax: true

在layout/global.ejs添加如下代码，以使得渲染器支持数学公式

  &lt;!-- 数学公式 --&gt;&lt;%- css(&#x27;css/mathjax.css&#x27;) %&gt;&lt;%- js(&#x27;js/mathjax.js&#x27;) %&gt;

添加样式文件source/css/mathjax.css使得渲染器渲染出字体为Times New Roman。以及支持让公式在小屏幕下自动换行

  /*  mathjax.css  用于美化 MathJax 渲染的数学公式字体和排版*/.mathjax-formula &#123;    font-family: &#x27;Times New Roman&#x27;, Times, serif;    font-size: 1.05em;    line-height: 1.5;&#125;  /* 让公式在小屏幕下自动换行 */.MathJax_Display &#123;    overflow-x: auto;    overflow-y: hidden;    width: 100%;    box-sizing: border-box;&#125;

添加脚本文件source/js/mathjax.js如下：

  /** * highlight.js * 代码块功能主入口，负责： * 1. 语法高亮初始化 * 2. 代码块头部（语言、复制、主题切换）生成 * 3. 主题切换逻辑 */(function() &#123;    // 动态加载 MathJax 脚本    var script = document.createElement(&#x27;script&#x27;);    script.type = &#x27;text/javascript&#x27;;    script.src = window.THEME_CONFIG.mathjax.src ||      &#x27;https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js&#x27;;    script.async = true;      // 可选：自定义 MathJax 配置    window.MathJax = &#123;      tex: &#123;        inlineMath: [[&#x27;$&#x27;, &#x27;$&#x27;], [&#x27;\\(&#x27;, &#x27;\\)&#x27;]]      &#125;      // 其他配置可按需添加    &#125;;      document.head.appendChild(script);  &#125;)();
(文章主体) 去掉标题前的符号#
作者不喜欢标题符号的设计，注释掉上面source/css/post.css中的以下代码即可：
  .post-content h1::before,.post-content h2::before,.post-content h3::before,.post-content h4::before,.post-content h5::before,.post-content h6::before &#123;  content: &quot;⌗&quot;;  padding-right: 10px;  color: var(--color-hashtag);  font-weight: 600;&#125;
(文章主体) 在无序列表前面加点
作者更习惯在无序列表前加点，修改source/css/root.css中的全局样式，
注释掉原来的样式，替换成如下样式
  /* ul,ol &#123;  list-style: none;&#125; */.post-content ul &#123;  list-style: disc;  padding-left: 2em; /* 保证缩进美观 */&#125;.post-content ul ul &#123;  list-style: circle;&#125;
(文章可选配置) 标题自动编号

在配置文件（如 _config.typo.yml 或 themes/shiroi/_config.yml）中添加开关

  heading_numbering: true

在 layout/_partial/head.ejs 的 &lt;/head&gt; 前注入两个文件。

  &lt;!-- 标题编号 --&gt;&lt;% if (theme.heading_numbering || config.heading_numbering) &#123; %&gt;  &lt;%- css(&#x27;css/heading-numbering.css&#x27;) %&gt;  &lt;%- js(&#x27;js/heading-numbering.js&#x27;) %&gt;&lt;% &#125; %&gt;&lt;/head&gt;

新建一个文件 source/js/heading-numbering.js，内容如下：

  document.addEventListener(&#x27;DOMContentLoaded&#x27;, function () &#123;    // 只在文章页生效    if (!document.querySelector(&#x27;.post&#x27;)) return;      // 只处理 h2-h6    const headings = document.querySelectorAll(&#x27;.post h2, .post h3, .post h4, .post h5, .post h6&#x27;);    const nums = [0, 0, 0, 0, 0]; // 对应 h2-h6      headings.forEach(heading =&gt; &#123;      const level = parseInt(heading.tagName[1]) - 2; // h2-&gt;0, h3-&gt;1, ...      if (level &lt; 0) return; // 跳过 h1        // 当前级别+1，低级别归零      nums[level]++;      for (let i = level + 1; i &lt; nums.length; i++) nums[i] = 0;        // 生成编号字符串      const numbering = nums.slice(0, level + 1).join(&#x27;.&#x27;);        // 插入编号      heading.innerHTML = `&lt;span class=&quot;heading-number&quot;&gt;$&#123;numbering&#125; &lt;/span&gt;` + heading.innerHTML;    &#125;);  &#125;);

新建一个文件 source/css/heading-numbering.css，内容如下：

  .heading-number &#123;  color: #888;  font-weight: normal;  margin-right: 0.5em;  font-size: 0.95em;&#125;
(文章可选配置) 三线表样式
此功能用于将标准的 Markdown 表格渲染为学术论文中常见的三线表样式，以增强可读性和专业性。该功能可通过主题配置文件中的开关进行控制。

首先，在主题配置文件 _config.yml 中添加以下开关：

  # Table stylethree_line_table: true

在 themes/shiroi/layout/_partial/head.ejs 中添加以下代码，以根据配置开关加载样式文件：

  &lt;!-- 三线表样式 --&gt;&lt;% if (theme.three_line_table) &#123; %&gt;  &lt;%- css(&#x27;css/three-line-table.css&#x27;) %&gt;&lt;% &#125; %&gt;

新建一个文件source/css/three-line-table.css ，内容如下。


为了避免样式污染用于代码块的表格（它们在渲染后也是 &lt;table&gt; 结构）,
所有规则都使用了 :not(.hljs) 选择器进行限定。

  /* Three-line table style, excluding tables used for code blocks */.post-content table:not(.hljs) &#123;  width: 100%;  border-collapse: collapse;  border-top: 2px solid var(--color-post-content, #333);  border-bottom: 2px solid var(--color-post-content, #333);  margin: 1.5em 0;  font-size: 0.95em;&#125;.post-content table:not(.hljs) th,.post-content table:not(.hljs) td &#123;  border: none;  padding: 0.75em 1em;  text-align: left;&#125;.post-content table:not(.hljs) thead th &#123;  border-bottom: 1px solid var(--color-post-content, #333);  text-align: center;  font-weight: 600;&#125;.post-content table:not(.hljs) tbody tr:nth-child(even) &#123;  background-color: var(--color-table-row, #f9f9f9);&#125;.post-content table:not(.hljs) caption &#123;  caption-side: bottom;  text-align: center;  font-size: 0.9em;  color: #888;  margin-top: 0.5em;&#125;
(文章可选配置) 图片样式
此功能用于自动居中图片，并将其 alt 文本作为带编号的图注（例如"图1：xxx"）显示。

在主题配置文件 _config.yaml 中添加以下开关：

  # Image settingsimage:  enable: true  # 总开关  center: true  # 居中图片  caption: true # 将 alt 文本作为带编号的图注显示

修改布局文件来注入样式资源

在 layout/_partial/head.ejs 中注入样式：
  &lt;!-- 图片样式 --&gt;&lt;% if (theme.image &amp;&amp; theme.image.enable) &#123; %&gt;&lt;%- css(&#x27;css/image-handler.css&#x27;) %&gt;&lt;% &#125; %&gt;
在 layout/layout.ejs 的 &lt;body&gt; 标签内部添加配置注入：
  &lt;body  &lt;% if (theme.image &amp;&amp; theme.image.enable) &#123; %&gt;    data-image-center=&quot;&lt;%= theme.image.center ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;    data-image-caption=&quot;&lt;%= theme.image.caption ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;  &lt;% &#125; %&gt;&gt;

新建文件 source/css/image-handler.css 。


我们使用 display: table; 技巧让 &lt;figure&gt; 元素的宽度自适应其内容，
从而使 margin: auto; 能够生效，实现真正的居中。

  .post-content .image-figure &#123;  /* This makes the figure shrink-wrap its content, allowing margin:auto to work */  display: table;  margin-left: auto;  margin-right: auto;&#125;.post-content .image-figure figcaption &#123;  margin-top: 0.8em;  font-size: 0.9em;  color: #888;  text-align: center; /* Explicitly center the caption text */&#125;

新建文件 source/js/image-handler.js 。


此脚本会查找文章中被单独包裹在 &lt;p&gt; 标签里的图片，
用一个带有 .image-figure 类的 &lt;figure&gt; 元素替换掉原来的 &lt;p&gt; 标签，
并根据配置添加图注。
通过 document.body.dataset 读取配置，完全解耦 JS 与模板。

  /** * image-handler.js * 自动居中图片，并为图片添加带编号的图注（如 &quot;图1：xxx&quot;） * 配置通过 &lt;body data-image-center=&quot;true&quot; data-image-caption=&quot;true&quot;&gt; 注入 */document.addEventListener(&#x27;DOMContentLoaded&#x27;, () =&gt; &#123;  const body = document.body;  const center = body.dataset.imageCenter === &#x27;true&#x27;;  const caption = body.dataset.imageCaption === &#x27;true&#x27;;  if (!center &amp;&amp; !caption) return;  let imageCounter = 0;  const content = document.querySelector(&#x27;.post-content&#x27;);  if (!content) return;  const images = content.querySelectorAll(&#x27;img&#x27;);  images.forEach(img =&gt; &#123;    const parent = img.parentNode;    // 只处理被单独包裹在 &lt;p&gt; 标签里的图片    if (parent.tagName === &#x27;P&#x27; &amp;&amp; parent.children.length === 1) &#123;      if (caption &amp;&amp; img.alt) &#123;        imageCounter++;        const figure = document.createElement(&#x27;figure&#x27;);        figure.classList.add(&#x27;image-figure&#x27;);        const figcaption = document.createElement(&#x27;figcaption&#x27;);        figcaption.innerText = `图 $&#123;imageCounter&#125;: $&#123;img.alt&#125;`;        // 移动图片到新 figure        figure.appendChild(img);        figure.appendChild(figcaption);        // 替换原 &lt;p&gt; 标签        parent.parentNode.replaceChild(figure, parent);      &#125; else if (center) &#123;        // 没有图注时，仅居中        parent.style.textAlign = &#x27;center&#x27;;      &#125;    &#125;  &#125;);&#125;);
(文章可选配置) 代码块样式升级
此功能旨在将默认的代码块替换为一个功能更丰富、样式更现代的组件。
它包含一个标题栏，用于显示代码语言和提供一键复制功能，并采用了仅保留关键分割线的极简设计。
最小化注释全局干扰样式
在source/css/post.css中，注释掉如下代码。
/*.post-content table td,.post-content table th &#123;  border: 1px solid #6b6b6b;  padding: 6px 13px;&#125;.post-content table tr &#123;  border-top: 1px solid #c6cbd1;&#125;*/
功能开关与配置
在主题配置文件 _config.shiroi.yml 中添加以下配置，用于控制复制按钮的显示内容。
# Code block settingscode_block:  # When copy_button is empty, the button displays the word &quot;copy&quot;.  # If a path to an SVG is provided, the SVG will be displayed as a clickable button.  copy_button: icon/copy.svg
代码块逻辑集成
在 themes/shiroi/source/js/code-block.js 文件中，实现了如下功能

初始化 highlight.js;
创建代码块头部;
添加复制功能;
主题切换功能;


此项目依赖 highlight.js 库，确保它已被引入。

// themes/shiroi/source/js/code-block.js// 确保 highlight.js 库已初始化if (typeof hljs !== &#x27;undefined&#x27;) &#123;  hljs.highlightAll();&#125;document.addEventListener(&#x27;DOMContentLoaded&#x27;, () =&gt; &#123;  const codeBlocks = document.querySelectorAll(&#x27;figure.highlight&#x27;);  const bodyDataset = document.body.dataset;  // 从 body 的 data-属性中获取配置  const copyButtonConfig = bodyDataset.codeBlockCopyButton;  const themeToggleEnable = bodyDataset.codeBlockThemeToggleEnable === &#x27;true&#x27;;  const themeToggleConfig = &#123;    enable: themeToggleEnable,    to_light_button: bodyDataset.codeBlockThemeToggleToLightButton,    to_dark_button: bodyDataset.codeBlockThemeToggleToDarkButton,  &#125;;  codeBlocks.forEach(codeBlock =&gt; &#123;    // 防止重复创建头部    if (codeBlock.querySelector(&#x27;.code-block-header&#x27;)) return;    // 添加 .hljs 类以防止三线表样式冲突    const table = codeBlock.querySelector(&#x27;table&#x27;);    if (table) &#123;      table.classList.add(&#x27;hljs&#x27;);    &#125;    // 获取语言名称    const lang = Array.from(codeBlock.classList).find(cls =&gt; cls !== &#x27;highlight&#x27;) || &#x27;code&#x27;;    // *** 函数定义：创建代码块头部 ***    const createCodeBlockHeader = (langName) =&gt; &#123;      const header = document.createElement(&#x27;div&#x27;);      header.className = &#x27;code-block-header&#x27;;      const langSpan = document.createElement(&#x27;span&#x27;);      langSpan.className = &#x27;code-lang-name&#x27;;      langSpan.innerText = langName;      header.appendChild(langSpan);      const actionsContainer = document.createElement(&#x27;div&#x27;);      actionsContainer.className = &#x27;code-block-actions&#x27;;      header.appendChild(actionsContainer);      return &#123; header, actionsContainer &#125;;    &#125;;    // *** 函数定义：添加复制按钮 ***    const addCopyButton = (actionsContainer, codeBlock, copyButtonPath) =&gt; &#123;      const container = document.createElement(&#x27;div&#x27;);      container.className = &#x27;copy-btn-container&#x27;;      const copyButton = document.createElement(&#x27;button&#x27;);      copyButton.className = &#x27;copy-btn&#x27;;      let originalContent;      if (copyButtonPath) &#123;        const icon = document.createElement(&#x27;img&#x27;);        icon.src = &#x27;/&#x27; + copyButtonPath;        copyButton.appendChild(icon);        originalContent = icon.outerHTML;      &#125; else &#123;        copyButton.innerText = &#x27;copy&#x27;;        originalContent = &#x27;copy&#x27;;      &#125;      container.appendChild(copyButton);      actionsContainer.appendChild(container);      copyButton.addEventListener(&#x27;click&#x27;, () =&gt; &#123;        const codeToCopy = codeBlock.querySelector(&#x27;.code&#x27;).innerText;        navigator.clipboard.writeText(codeToCopy).then(() =&gt; &#123;          copyButton.innerText = &#x27;copied!&#x27;;          setTimeout(() =&gt; &#123;            copyButton.innerHTML = originalContent;          &#125;, 3000);        &#125;).catch(err =&gt; &#123;          console.error(&#x27;Failed to copy text: &#x27;, err);        &#125;);      &#125;);    &#125;;    // *** 函数定义：添加主题切换按钮 ***    const addThemeToggleButton = (actionsContainer, codeBlock, toggleConfig) =&gt; &#123;      if (!toggleConfig || !toggleConfig.enable) return;      const lightButton = document.createElement(&#x27;button&#x27;);      lightButton.className = &#x27;theme-toggle-btn light&#x27;;      const lightIcon = document.createElement(&#x27;img&#x27;);      lightIcon.src = &#x27;/&#x27; + toggleConfig.to_dark_button;      lightButton.appendChild(lightIcon);      const darkButton = document.createElement(&#x27;button&#x27;);      darkButton.className = &#x27;theme-toggle-btn dark&#x27;;      const darkIcon = document.createElement(&#x27;img&#x27;);      darkIcon.src = &#x27;/&#x27; + toggleConfig.to_light_button;      darkButton.appendChild(darkIcon);      // Initial state: assume light theme is default      darkButton.style.display = &#x27;inline-block&#x27;;      lightButton.style.display = &#x27;none&#x27;;      actionsContainer.appendChild(lightButton);      actionsContainer.appendChild(darkButton);      darkButton.addEventListener(&#x27;click&#x27;, () =&gt; &#123;        const figure = darkButton.closest(&#x27;figure.highlight&#x27;);        if (figure) &#123;          figure.classList.remove(&#x27;theme-light&#x27;);          figure.classList.add(&#x27;theme-dark&#x27;);        &#125;        darkButton.style.display = &#x27;none&#x27;;        lightButton.style.display = &#x27;inline-block&#x27;;      &#125;);      lightButton.addEventListener(&#x27;click&#x27;, () =&gt; &#123;        const figure = lightButton.closest(&#x27;figure.highlight&#x27;);        if (figure) &#123;          figure.classList.remove(&#x27;theme-dark&#x27;);          figure.classList.add(&#x27;theme-light&#x27;);        &#125;        lightButton.style.display = &#x27;none&#x27;;        darkButton.style.display = &#x27;inline-block&#x27;;      &#125;);    &#125;;    // 创建代码块头部    const &#123; header, actionsContainer &#125; = createCodeBlockHeader(lang);    codeBlock.prepend(header);    // 添加复制按钮    if (copyButtonConfig) &#123;      addCopyButton(actionsContainer, codeBlock, copyButtonConfig);    &#125;    // 添加主题切换按钮    if (themeToggleConfig.enable) &#123;      addThemeToggleButton(actionsContainer, codeBlock, themeToggleConfig);      // 默认设置为浅色主题，与CSS变量的默认值保持一致      codeBlock.classList.add(&#x27;theme-light&#x27;);    &#125;  &#125;);&#125;);
CSS 样式集成
在 themes/shiroi/source/css/code-block-base.css 文件中集成所有基础样式。

这份样式表经过了多次迭代，拥有极高的优先级，能够覆盖主题中其他冲突的全局样式，确保最终效果的稳定。

/* themes/shiroi/source/css/code-block-base.css *//*  Shiroi Code Block Styling - FINAL  - A clean, headered code block with CSS Variables for theming.  - Language display and copy button  - Only two separator lines: one under the header, one between line numbers and code.  - Fix for rounded corners and persistent borders.*//*  Define all themeable properties as CSS variables with light theme defaults.  Dark theme (or any other theme) will override these variables.*/figure.highlight &#123;  --code-bg: #f7f7f7; /* Overall background of the container */  --header-bg: #f7f7f7; /* Header background */  --table-bg: white; /* Code area background */  --gutter-bg: #f7f7f7; /* Line number background, same as header */  --border-color: #eee; /* All separator lines */  --lang-name-color: #555; /* Language name text color */  border-radius: 8px;  margin: 1.5em 0;  overflow: hidden;  background-color: var(--code-bg);&#125;/* Add a class to the figure when in dark mode to switch themes */figure.highlight.theme-dark &#123;  --code-bg: #282c34;  --header-bg: #21252b;  --table-bg: #282c34;  --gutter-bg: #21252b;  --border-color: #3a4049;  --lang-name-color: #abb2bf;&#125;/* Header for language name and copy button */.code-block-header &#123;  display: flex;  justify-content: space-between;  align-items: center;  padding: 0.5em 1em;  background-color: var(--header-bg);  border-bottom: 1px solid var(--border-color); /* Horizontal separator */&#125;.code-lang-name &#123;  font-size: 0.9em;  color: var(--lang-name-color);  text-transform: capitalize;  font-family: &#x27;JetBrains Mono&#x27;, monospace;&#125;/* Copy button styling */.copy-btn-container .copy-btn &#123;  border: none;  cursor: pointer;  background-color: transparent;  opacity: 0.6;&#125;.copy-btn-container .copy-btn:hover &#123;  opacity: 1;&#125;/* Ensure all button images (copy and theme toggle) have consistent size */.copy-btn-container .copy-btn img,.code-block-actions .theme-toggle-btn img &#123;  width: 16px;  height: 16px;  vertical-align: middle;&#125;/* --- OVERRIDES FOR CONFLICTING GLOBAL STYLES --- *//* This is the container for the code proper */figure.highlight table.hljs &#123;  background-color: var(--table-bg);  width: 100%;  margin: 0;  border-spacing: 0;  border-radius: 0 0 8px 8px;&#125;/* Nuke all borders on table cells from other stylesheets with high specificity */.post-content figure.highlight table.hljs td &#123;  border: none !important;  padding: 0 !important; /* Reset padding before applying it below */&#125;/* Apply padding and the vertical separator ONLY where intended */.post-content figure.highlight table.hljs .gutter &#123;  background-color: var(--gutter-bg);  padding: 1em !important;  border-right: 1px solid var(--border-color) !important; /* The one true vertical line */&#125;.post-content figure.highlight table.hljs .code &#123;  padding: 1em !important;&#125;/* Also color the gutter text */.post-content figure.highlight table.hljs .gutter .line &#123;  color: var(--lang-name-color); /* Use the same color as the lang name for now */  opacity: 0.5;&#125;
模板注入
为了让上述功能生效，需要在模板文件中引入对应的CSS和JS，并将配置通过 body 标签的 data- 属性注入。
在 themes/shiroi/layout/_partial/head.ejs 中添加：
&lt;!-- 代码块基础样式 --&gt;&lt;%- css(&#x27;css/code-block-base.css&#x27;) %&gt;&lt;!-- Codeblock Theme Toggler CSS --&gt;&lt;% if (theme.code_block &amp;&amp; theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.enable) &#123; %&gt;&lt;%- css(&#x27;css/codeblock-theme-toggle.css&#x27;) %&gt;&lt;% &#125; %&gt;
在 themes/shiroi/layout/layout.ejs 的 &lt;body&gt; 标签内部添加配置注入：
&lt;body  &lt;% if (theme.image &amp;&amp; theme.image.enable) &#123; %&gt;    data-image-center=&quot;&lt;%= theme.image.center ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;    data-image-caption=&quot;&lt;%= theme.image.caption ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;  &lt;% &#125; %&gt;  &lt;% if (theme.code_block) &#123; %&gt;    data-code-block-copy-button=&quot;&lt;%= theme.code_block.copy_button || &#x27;&#x27; %&gt;&quot;    data-code-block-theme-toggle-enable=&quot;&lt;%= (theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.enable) ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;    data-code-block-theme-toggle-to-light-button=&quot;&lt;%= (theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.to_light_button) || &#x27;&#x27; %&gt;&quot;    data-code-block-theme-toggle-to-dark-button=&quot;&lt;%= (theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.to_dark_button) || &#x27;&#x27; %&gt;&quot;  &lt;% &#125; %&gt;&gt;
在 themes/shiroi/layout/post.ejs 的末尾引入逻辑脚本：
&lt;%- js(&#x27;js/code-block-header.js&#x27;) %&gt;&lt;%- js(&#x27;js/code-block-copy.js&#x27;) %&gt;&lt;%- js(&#x27;js/code-block-theme-toggle.js&#x27;) %&gt;&lt;%- js(&#x27;js/code-block.js&#x27;) %&gt;
代码块昼夜切换主题样式,
在code_block:中添加子选项
theme_toggle:  enable: true  to_light_button: icon/light-codeblock.svg  to_dark_button: icon/dark-codeblock.svg
我们的设计是将点击代码块右上方的昼夜切换按钮，可以实现代码块内部的深浅主题切换。

当按钮是to_light_button，切换至浅色主题。
当按钮是to_dark_button，切换至深色主题。
代码块内部的主题由  light_theme dark_theme配置，
它们可以是source/css中的css文件；
也可以是指向css的 URL。

最终架构的基础布局的颜色由一组CSS变量控制，这些变量在 code-block-base.css 中定义并拥有浅色主题的默认值。
切换主题时，JavaScript仅在代码块的根元素(&lt;figure&gt;)上添加一个 .theme-dark 类，这个类会激活一组新的CSS变量值，从而瞬间改变所有基础颜色。
vscode-modern-light.css 和 vscode-modern-dark.css 文件只负责定义对应主题下的语法高亮文本颜色，并且其规则分别被 .theme-light 和 .theme-dark 类所限定。
我们设计了一个 themes/shiroi/source/js/code-block.js 的统一脚本。所有DOM操作，包括创建标题栏、语言名称、主题切换按钮和复制按钮的逻辑，全部被整合到该脚本中，确保了正确的执行顺序，避免了时序冲突和元素重复创建。
类名切换能即时生效
我们在 layout/_partial/head.ejs 中同时加载浅色和深色两个主题的CSS文件。
&lt;!-- themes/shiroi/layout/_partial/head.ejs --&gt;&lt;% if (is_post())&#123; %&gt;  &lt;% if (theme.code_block &amp;&amp; theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.enable) &#123; %&gt;    &lt;%- css(theme.code_block.theme_toggle.light_theme) %&gt;    &lt;%- css(theme.code_block.theme_toggle.dark_theme) %&gt;  &lt;% &#125; else &#123; %&gt;    &lt;link rel=&quot;stylesheet&quot; href=&quot;https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.9.0/styles/atom-one-light.css&quot;&gt;  &lt;% &#125; %&gt;  &lt;script src=&quot;https://unpkg.com/@highlightjs/cdn-assets@11.9.0/highlight.min.js&quot;&gt;&lt;/script&gt;&lt;% &#125; %&gt;
设计核心样式
code-block-base.css文件被重构为使用CSS变量。它定义了浅色主题的默认颜色，并包含一个 .theme-dark 类用于覆盖这些变量以实现深色主题。
/* themes/shiroi/source/css/code-block-base.css */figure.highlight &#123;  --code-bg: #f7f7f7;  --header-bg: #f7f7f7;  --table-bg: white;  --gutter-bg: #f7f7f7;  --border-color: #eee;  --lang-name-color: #555;  /* ...其他样式... */  background-color: var(--code-bg);&#125;figure.highlight.theme-dark &#123;  --code-bg: #282c34;  --header-bg: #21252b;  --table-bg: #282c34;  --gutter-bg: #21252b;  --border-color: #3a4049;  --lang-name-color: #abb2bf;&#125;
vscode-modern-dark.css 和 vscode-modern-light.css这两个文件现在只包含被 .theme-dark 或 .theme-light 限定的文本颜色规则。这两个文件可以充分的自定义。
统一脚本 (code-block.js)
这是所有魔法发生的地方。它在页面加载后执行以下操作：

遍历所有代码块。
检查并防止重复创建标题栏。
为每个代码块默认添加 .theme-light 类。
从 body 标签的 data- 属性中读取配置。
动态创建完整的标题栏，包括语言名称、主题切换器和复制按钮，所有相关函数均在此文件中定义。
为按钮绑定事件监听器。点击时，脚本只做一件事：在 &lt;figure&gt; 元素上切换 .theme-light 和 .theme-dark 类。
至此，整个功能改造完成，系统稳定、高效且易于维护。在完成上述重构后，语法高亮功能得以完美实现。


注意1：解决根源上的类名不匹配问题
之前遇到的问题根源在于Hexo的 _config.yml 文件中的 highlight.hljs: false 配置，它阻止了hljs-前缀的生成。我们通过以下方式解决了这个问题：

恢复配置: 我们将 _config.yml 中的 hljs 选项保持为 false，确保代码块能正确地渲染为多行。
改造主题CSS: 我们对 vscode-modern-light.css 和 vscode-modern-dark.css 其中所有的 .hljs- 前缀全部移除，并修正了基础文本颜色的选择器，使其与渲染器输出的HTML完全匹配。
例如，在 vscode-modern-dark.css 中：

/* 修改前 */.post-content figure.highlight.theme-dark .code .hljs-keyword &#123; color: #c678dd;&#125;/* 修改后 */.post-content figure.highlight.theme-dark .code .keyword &#123; color: #c678dd;&#125;
通过这次修改，CSS规则最终与渲染器输出的HTML完全匹配，语法高亮功能也得以完美实现。


注意2: 解决样式冲突！我们采用高优先级地办法保证了功能的独立性和可维护性。
在调试过程中，我们发现全局样式对代码块造成了严重干扰。为了确保样式稳定生效，我们采取了以下方案：

在 themes/shiroi/source/css/post.css 中注释掉了旧的表格样式。
在 themes/shiroi/source/css/code-block-base.css 中使用了高优先级、高特异性的CSS选择器来覆盖其他冲突样式。


代码块标题栏 Mac 主题风格增强
代码块标题栏 Mac主题增强可以通过开关打开，在配置文件中添加
# codeblockcode_block:  style: default  copy_button: icon/copy.svg    # Theme toggling for code blocks  # Requires `light_theme` and `dark_theme` to be enabled.  theme_toggle:    enable: true    to_light_button: icon/light-codeblock.svg    to_dark_button: icon/dark-codeblock.svg    light_theme: css/vscode-modern-light.css    dark_theme: css/vscode-modern-dark.css    mac_enhancier:       enable: true      init_folded_status: true # 新增：控制代码块初始是否折叠，仅在mac_enhancier启用时生效
此功能将在代码块标题栏左侧添加Mac风格的交通灯图标，点击交通灯可以实现代码块的折叠与展开。
当 mac_enhancier 启用且 init_folded_status 为 true 时，代码块将默认以折叠状态显示。
实现细节


CSS 文件 (themes/shiroi/source/css/code-block-mac-enhancer.css)：
新建 themes/shiroi/source/css/code-block-mac-enhancer.css，用于定义Mac风格标题栏的样式和代码块折叠/展开的动画效果。
/* themes/shiroi/source/css/code-block-mac-enhancer.css */.code-block-header.mac-style &#123;  position: relative;  padding-left: 70px; /* Make space for buttons */&#125;.code-block-header.mac-style .code-lang-name &#123;  text-align: center;  flex-grow: 1; /* Allow language name to center properly */&#125;.mac-traffic-lights &#123;  position: absolute;  left: 15px;  top: 50%;  transform: translateY(-50%);  display: flex;  gap: 6px; /* Space between circles */&#125;.mac-traffic-lights .dot &#123;  width: 12px;  height: 12px;  border-radius: 50%;  border: 0.5px solid rgba(0, 0, 0, 0.1);&#125;.mac-traffic-lights .dot.red &#123;  background-color: #ff5f56;&#125;.mac-traffic-lights .dot.yellow &#123;  background-color: #ffbd2e;&#125;.mac-traffic-lights .dot.green &#123;  background-color: #27c93f;&#125;/* Code block collapse/expand styles */figure.highlight.is-collapsed table.hljs &#123;  max-height: 0;  overflow: hidden;  transition: max-height 0.3s ease-out;&#125;figure.highlight table.hljs &#123;  max-height: 9999px; /* A large value to ensure content is visible when expanded */  transition: max-height 0.3s ease-in;&#125;


JavaScript 逻辑 (themes/shiroi/source/js/code-block.js)：
在 themes/shiroi/source/js/code-block.js 文件中，新增 macEnhancerEnable 和 initFoldedStatus 的配置读取，并在 macEnhancerEnable 启用时，根据 initFoldedStatus 的值来初始折叠代码块。
同时，为交通灯容器添加点击事件监听器，用于切换代码块的 is-collapsed 类。
以下是相关核心逻辑的更新：
// themes/shiroi/source/js/code-block.js// ... (其他现有代码) ...document.addEventListener(&#x27;DOMContentLoaded&#x27;, () =&gt; &#123;  const codeBlocks = document.querySelectorAll(&#x27;figure.highlight&#x27;);  const bodyDataset = document.body.dataset;  // 从 body 的 data-属性中获取配置  const copyButtonConfig = bodyDataset.codeBlockCopyButton;  const themeToggleEnable = bodyDataset.codeBlockThemeToggleEnable === &#x27;true&#x27;;  const macEnhancerEnable = bodyDataset.codeBlockMacEnhancer === &#x27;true&#x27;;  const initFoldedStatus = bodyDataset.codeBlockMacEnhancerInitFoldedStatus === &#x27;true&#x27;; // 新增：初始折叠状态开关    const themeToggleConfig = &#123;    enable: themeToggleEnable,    to_light_button: bodyDataset.codeBlockThemeToggleToLightButton,    to_dark_button: bodyDataset.codeBlockThemeToggleToDarkButton,  &#125;;  codeBlocks.forEach(codeBlock =&gt; &#123;    // ... (其他现有代码) ...    // *** 函数定义：添加Mac风格交通灯 ***    const addMacTrafficLights = (header) =&gt; &#123;      header.classList.add(&#x27;mac-style&#x27;);      const trafficLightsContainer = document.createElement(&#x27;div&#x27;);      trafficLightsContainer.className = &#x27;mac-traffic-lights&#x27;;      const redDot = document.createElement(&#x27;span&#x27;);      redDot.className = &#x27;dot red&#x27;;      trafficLightsContainer.appendChild(redDot);      const yellowDot = document.createElement(&#x27;span&#x27;);      yellowDot.className = &#x27;dot yellow&#x27;;      trafficLightsContainer.appendChild(yellowDot);      const greenDot = document.createElement(&#x27;span&#x27;);      greenDot.className = &#x27;dot green&#x27;;      trafficLightsContainer.appendChild(greenDot);      header.prepend(trafficLightsContainer);      // Add click event to toggle collapse      trafficLightsContainer.addEventListener(&#x27;click&#x27;, () =&gt; &#123;        codeBlock.classList.toggle(&#x27;is-collapsed&#x27;);      &#125;);    &#125;;    // 添加Mac风格增强    if (macEnhancerEnable) &#123;      addMacTrafficLights(header);      // 如果init_folded_status为true，则初始自动折叠代码块      if (initFoldedStatus) &#123;        codeBlock.classList.add(&#x27;is-collapsed&#x27;);      &#125;    &#125;  &#125;);&#125;);


布局文件更新:

themes/shiroi/layout/layout.ejs：
在 &lt;body&gt; 标签中添加 data-code-block-mac-enhancer 和 data-code-block-mac-enhancer-init-folded-status 属性。&lt;body  &lt;% if (theme.image &amp;&amp; theme.image.enable) &#123; %&gt;    data-image-center=&quot;&lt;%= theme.image.center ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;    data-image-caption=&quot;&lt;%= theme.image.caption ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;  &lt;% &#125; %&gt;  &lt;% if (theme.code_block) &#123; %&gt;    data-code-block-copy-button=&quot;&lt;%= theme.code_block.copy_button || &#x27;&#x27; %&gt;&quot;    data-code-block-theme-toggle-enable=&quot;&lt;%= (theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.enable) ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;    data-code-block-theme-toggle-to-light-button=&quot;&lt;%= (theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.to_light_button) || &#x27;&#x27; %&gt;&quot;    data-code-block-theme-toggle-to-dark-button=&quot;&lt;%= (theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.to_dark_button) || &#x27;&#x27; %&gt;&quot;    &lt;% if (theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.mac_enhancier) &#123; %&gt;    data-code-block-mac-enhancer=&quot;true&quot;    data-code-block-mac-enhancer-init-folded-status=&quot;&lt;%= (theme.code_block.theme_toggle.mac_enhancier.init_folded_status) ? &#x27;true&#x27; : &#x27;false&#x27; %&gt;&quot;    &lt;% &#125; else &#123; %&gt;    data-code-block-mac-enhancer=&quot;false&quot;    data-code-block-mac-enhancer-init-folded-status=&quot;false&quot;    &lt;% &#125; %&gt;  &lt;% &#125; %&gt;&gt;

themes/shiroi/layout/_partial/head.ejs：
条件性地加载 code-block-mac-enhancer.css。&lt;!-- Codeblock Mac Enhancer CSS --&gt;&lt;% if (theme.code_block &amp;&amp; theme.code_block.theme_toggle &amp;&amp; theme.code_block.theme_toggle.mac_enhancier &amp;&amp; theme.code_block.theme_toggle.mac_enhancier.enable) &#123; %&gt;&lt;%- css(&#x27;css/code-block-mac-enhancer.css&#x27;) %&gt;&lt;% &#125; %&gt;




