选项

  title: tagsdate: 2025-06-26 13:52:55type: &quot;tags&quot;layout: &quot;tags&quot;

创建文件layout/tags.ejs

    &lt;div class=&quot;tag-overview-container&quot;&gt;  &lt;!-- &lt;h2 class=&quot;page-title&quot;&gt;所有标签&lt;/h2&gt; --&gt;  &lt;div class=&quot;tag-card-grid&quot;&gt;    &lt;% site.tags.sort(&#x27;name&#x27;).each(function(tag)&#123; %&gt;      &lt;a class=&quot;tag-card&quot; data-tag-name=&quot;&lt;%= tag.name %&gt;&quot;&gt;        &lt;div class=&quot;tag-card-icon&quot;&gt;          &lt;img src=&quot;&lt;%= url_for(&#x27;icon/tag-icon.svg&#x27;) %&gt;&quot; alt=&quot;Tag Icon&quot; style=&quot;width:1.2em;height:1.2em;vertical-align:middle;&quot;&gt;        &lt;/div&gt;        &lt;div class=&quot;tag-card-info&quot;&gt;          &lt;span class=&quot;tag-card-name&quot;&gt;&lt;%= tag.name %&gt;&lt;/span&gt;          &lt;span class=&quot;tag-card-count&quot;&gt;(&lt;%= tag.posts.length %&gt;)&lt;/span&gt;        &lt;/div&gt;      &lt;/a&gt;    &lt;% &#125;) %&gt;  &lt;/div&gt;  &lt;div id=&quot;filtered-articles-container&quot; class=&quot;filtered-articles-container&quot;&gt;    &lt;!-- Articles will be dynamically loaded here --&gt;  &lt;/div&gt;  &lt;div id=&quot;all-posts-data&quot; data-posts=&#x27;&lt;%- JSON.stringify(site.posts.map(function(post)&#123; return &#123;title: post.title, path: url_for(post.path), tags: post.tags.map(function(tag)&#123; return tag.name; &#125;), date: date(post.date, &quot;YYYY-MM-DD&quot;)&#125; &#125;)) %&gt;&#x27;&gt;&lt;/div&gt;&lt;/div&gt; 

创建脚本文件source/js/tags-filters.js文件

    document.addEventListener(&#x27;DOMContentLoaded&#x27;, function() &#123;  const allPostsDataElement = document.getElementById(&#x27;all-posts-data&#x27;);  const filteredArticlesContainer = document.getElementById(&#x27;filtered-articles-container&#x27;);  let allPosts = [];  if (allPostsDataElement &amp;&amp; allPostsDataElement.dataset.posts) &#123;    try &#123;      allPosts = JSON.parse(allPostsDataElement.dataset.posts);    &#125; catch (e) &#123;      console.error(&#x27;Error parsing posts data:&#x27;, e);    &#125;  &#125;  const tagCards = document.querySelectorAll(&#x27;.tag-card&#x27;);  function renderArticles(articles) &#123;    if (articles.length === 0) &#123;      filteredArticlesContainer.innerHTML = &#x27;&lt;p&gt;暂无相关文章。&lt;/p&gt;&#x27;;      return;    &#125;    let html = &#x27;&lt;ul class=&quot;filtered-article-list&quot;&gt;&#x27;;    articles.forEach(article =&gt; &#123;      html += `        &lt;li class=&quot;filtered-article-list-item&quot;&gt;          &lt;span class=&quot;filtered-article-date&quot;&gt;$&#123;article.date&#125;&lt;/span&gt;          &lt;a href=&quot;$&#123;article.path&#125;&quot; class=&quot;filtered-article-title&quot;&gt;$&#123;article.title&#125;&lt;/a&gt;        &lt;/li&gt;      `;    &#125;);    html += &#x27;&lt;/ul&gt;&#x27;;    filteredArticlesContainer.innerHTML = html;  &#125;  tagCards.forEach(card =&gt; &#123;    card.addEventListener(&#x27;click&#x27;, function(event) &#123;      event.preventDefault(); // Prevent default link behavior      const tagName = this.dataset.tagName;      const filteredPosts = allPosts.filter(post =&gt; &#123;        return post.tags &amp;&amp; post.tags.includes(tagName);      &#125;);      renderArticles(filteredPosts);    &#125;);  &#125;);  // Optional: Initial rendering of all articles or a default tag&#x27;s articles  // renderArticles(allPosts);&#125;); 

创建样式文件tags.css

  .tag-overview-container &#123;  max-width: 900px;  margin: 40px auto;  padding: 20px;  background-color: #fff;&#125;.page-title &#123;  text-align: center;  margin-bottom: 30px;  color: #333;  font-size: 2em;&#125;.tag-card-grid &#123;  display: flex; /* Changed to Flexbox for better centering with wrapping */  flex-wrap: wrap; /* Allow items to wrap to the next line */  justify-content: center; /* Center flex items within their rows */  /* Removed grid-template-columns and gap as they are grid-specific */&#125;.tag-card &#123;  margin: 10px; /* Add margin for spacing between flex items */  display: flex;  align-items: center;  padding: 15px;  border: 1px solid #eee;  border-radius: 10px; /* Rounded corners for the card */  text-decoration: none;  color: inherit;  box-shadow: 0 2px 5px rgba(0,0,0,0.05);  transition: all 0.3s ease;&#125;.tag-card:hover &#123;  transform: translateY(-3px);  box-shadow: 0 4px 10px rgba(0,0,0,0.1);&#125;.tag-card-icon &#123;  width: 30px;  height: 30px;  margin-right: 10px;  display: flex; /* For centering SVG */  align-items: center;  justify-content: center;&#125;.tag-card-icon svg &#123;  width: 100%;  height: 100%;  fill: #007bff; /* Color for the SVG icon */&#125;.tag-card-info &#123;  flex-grow: 1;&#125;.tag-card-name &#123;  font-size: 1.2em;  font-weight: bold;  color: #333;&#125;.tag-card-count &#123;  font-size: 0.9em;  color: #777;  margin-left: 5px;&#125;/* Remove old styles no longer used */.tag-item-group,.tag-name,.tag-name a,.tag-name a:hover,.tag-post-list,.tag-post-list-item,.tag-post-list-item a,.tag-post-list-item a:hover,.tag-post-list-item time &#123;  display: none; /* Hide old elements */&#125;.filtered-articles-container &#123;  margin-top: 40px;  padding-top: 20px;  border-top: 1px solid #eee;&#125;.filtered-article-list &#123;  list-style: none;  padding-left: 0;&#125;.filtered-article-list-item &#123;  padding: 10px 0;  border-bottom: 1px dotted #f0f0f0;&#125;.filtered-article-list-item:last-child &#123;  border-bottom: none;&#125;.filtered-article-title &#123;  text-decoration: none;  color: #333;  font-size: 1.1em;  transition: color 0.2s ease;&#125;.filtered-article-title:hover &#123;  color: #007bff;&#125; 
添加about页（同步Github Profile）


本地克隆远端仓库git clone https://github.com/Kytolly/Kytolly.git


编写站点目录下编写同步脚本scripts/sync-about-page.js


  const fs = require(&#x27;fs&#x27;);const path = require(&#x27;path&#x27;);const LOCAL_README_PATH = path.join(__dirname, &#x27;..&#x27;, &#x27;resume&#x27;, &#x27;Kytolly&#x27;, &#x27;README.md&#x27;);const ABOUT_PAGE_PATH = path.join(__dirname, &#x27;..&#x27;, &#x27;source&#x27;, &#x27;about&#x27;, &#x27;index.md&#x27;);async function syncAboutPage() &#123;  try &#123;    console.log(&#x27;Reading local README content...&#x27;);    let githubReadmeContent = fs.readFileSync(LOCAL_README_PATH, &#x27;utf8&#x27;);    // Remove GitHub specific elements and unnecessary lines    githubReadmeContent = githubReadmeContent.replace(/&lt;\&gt;.*?&lt;\&gt;/g, &#x27;&#x27;); // Remove &lt; &gt; logo &lt; &gt;    githubReadmeContent = githubReadmeContent.replace(/!\[.*\]\(https:\/\/github-readme-stats\.vercel\.app\/api.*?\)/g, &#x27;&#x27;); // Remove GitHub stats images    githubReadmeContent = githubReadmeContent.replace(/&lt;script src=&quot;.*?&lt;\/script&gt;/g, &#x27;&#x27;); // Remove script tags    githubReadmeContent = githubReadmeContent.replace(/##\s*Repository files navigation[\s\S]*?##\s*About/g, &#x27;## About&#x27;); // Remove GitHub navigation section    githubReadmeContent = githubReadmeContent.split(&#x27;## About&#x27;)[0] + &#x27;## About\n&#x27; + githubReadmeContent.split(&#x27;## About&#x27;)[1]; // Keep the &#x27;About&#x27; section for now and manually adjust    githubReadmeContent = githubReadmeContent.replace(/\s*###\s*\n/g, &#x27;&#x27;); // Remove empty ### lines    // Read existing about page to preserve front-matter    const existingContent = fs.readFileSync(ABOUT_PAGE_PATH, &#x27;utf8&#x27;);    const frontMatterEndIndex = existingContent.indexOf(&#x27;---&#x27;, 3); // Find second --- after initial front-matter    let frontMatter = &#x27;&#x27;;    if (frontMatterEndIndex !== -1) &#123;      frontMatter = existingContent.substring(0, frontMatterEndIndex + 3);    &#125; else &#123;      // Fallback if no second --- found, assume basic front-matter      frontMatter = `---      title: 关于      date: $&#123;new Date().toISOString().split(&#x27;T&#x27;)[0]&#125; 12:00:00      layout: page      ---      `;    &#125;    // Combine front-matter with new content    const newContent = `$&#123;frontMatter&#125;\n\n$&#123;githubReadmeContent&#125;`;    fs.writeFileSync(ABOUT_PAGE_PATH, newContent, &#x27;utf8&#x27;);    console.log(&#x27;About page synchronized successfully with local README.&#x27;);  &#125; catch (error) &#123;    console.error(&#x27;Error synchronizing about page:&#x27;, error.message);  &#125;&#125;syncAboutPage(); 

创建页面hexo new page about

主题外配置
启用 syzoj_renderer

安装渲染器hexo-renderer-syzoj-renderer

  npm uninstall hexo-renderer-markednpm install hexo-renderer-syzoj-renderer

在配置文件_config_yml添加选项

  # syzoj-renderer configsyzoj_renderer:  cache_file: cache.json       # File to store cache, related to Hexo&#x27;s base directory.  highlighter: hexo           # Code highlighter, &#x27;prism&#x27; or &#x27;hexo&#x27;, the later uses highlight.js.  options:                     # syzoj-renderer&#x27;s options, see https://github.com/syzoj/syzoj-renderer.    highlight:      expandTab: null          # expandTab &gt; 0 to enable expand tab, which replaces one tab to that namy spaces.      wrapper:                 # Strings that&#x27;ll be added to highlighted code&#x27;s beginning and ending.        - &lt;pre&gt;&lt;code&gt;        - &lt;/code&gt;&lt;/pre&gt;    markdownItMergeCells: false # Enable markdown-it-merge-cells or not, which&#x27;ll merge adjacent cells with same                              # content in Markdown tables.    markdownIt:                # markdown-it&#x27;s options, see https://github.com/markdown-it/markdown-it.      html: true      breaks: false      linkify: true      typographer: false    markdownItMath:            # markdown-it-math-loose&#x27;s options, see https://github.com/Menci/markdown-it-math-loose.      inlineOpen: $      inlineClose: $      blockOpen: $$      blockClose: $$
启用 giscus

在站点配置文件_config.yml添加选项

  giscus:  enable: true  repo: Kytolly/MyGiscus  repo_id: R_kgDOK2X_9Q  category: Announcements  category_id: DIC_kwDOK2X_9c4Cbicm  mapping: pathname  strict: 0  reactions_enabled: 1  emit_metadata: 1  input_position: top  theme: preferred_color_scheme  lang: zh-CN  # loading: lazy

创建文件layout/_partial/giscus.ejs，内容如下：

  &lt;% if (config.giscus.enable &amp;&amp; (page.giscus !== false) ) &#123; %&gt;    &lt;script src=&quot;https://giscus.app/client.js&quot;      data-repo=&quot;&lt;%= config.giscus.repo %&gt;&quot;      data-repo-id=&quot;&lt;%= config.giscus.repo_id %&gt;&quot;      data-category=&quot;&lt;%= config.giscus.category %&gt;&quot;      data-category-id=&quot;&lt;%= config.giscus.category_id %&gt;&quot;      data-mapping=&quot;&lt;%= config.giscus.mapping %&gt;&quot;      data-strict=&quot;&lt;%= config.giscus.strict %&gt;&quot;      data-reactions-enabled=&quot;&lt;%= config.giscus.reactions_enabled %&gt;&quot;      data-emit-metadata=&quot;&lt;%= config.giscus.emit_metadata %&gt;&quot;      data-input-position=&quot;&lt;%= config.giscus.input_position %&gt;&quot;      data-theme=&quot;&lt;%= config.giscus.theme %&gt;&quot;      data-lang=&quot;&lt;%= config.giscus.lang %&gt;&quot;      data-loading=&quot;&lt;%= config.giscus.loading %&gt;&quot;      crossorigin=&quot;anonymous&quot;      async&gt;    &lt;/script&gt;  &lt;% &#125; %&gt;

在layout/post.ejs文件末尾注入配置

  &lt;!-- 插入giscus评论区 --&gt;&lt;%- partial(&#x27;_partial/giscus&#x27;) %&gt;

若有必要在某个文章中关闭评论区，在文章的Front Matter添加

giscus: false
